import React, { useId, useState } from "react";

interface IconProps extends React.SVGProps<SVGSVGElement> {
  size?: number | string;
}

interface JouleIconProps extends IconProps {
  isHovered?: boolean;
}

const createIcon = (
  pathData: string,
  fillRule?: "evenodd" | "nonzero"
): React.FC<IconProps> => {
  const Icon: React.FC<IconProps> = ({ size = 20, className, ...props }) => (
    <svg
      viewBox="0 0 20 20"
      width={size}
      height={size}
      fill="currentColor"
      className={className}
      {...props}
    >
      <path d={pathData} fillRule={fillRule} />
    </svg>
  );
  return Icon;
};

// SAP icons use 512x512 viewBox
const createSapIcon = (
  pathData: string,
  fillRule?: "evenodd" | "nonzero"
): React.FC<IconProps> => {
  const Icon: React.FC<IconProps> = ({ size = 20, className, ...props }) => (
    <svg
      viewBox="0 0 512 512"
      width={size}
      height={size}
      fill="currentColor"
      className={className}
      {...props}
    >
      <path d={pathData} fillRule={fillRule} />
    </svg>
  );
  return Icon;
};

